<div class="es">
<svg viewBox="0 0 700 480" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="32" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Los Dos Bandos de la Clarity Act — Oposición Bancaria vs. Apoyo Policial</text>
  <g font-family="sans-serif">
    <rect x="30" y="55" width="310" height="140" rx="10" fill="#2a1414" stroke="#f87171" stroke-width="1.3"/>
    <text x="185" y="80" fill="#fca5a5" font-size="14" font-weight="700" text-anchor="middle">Oposición Bancaria (13/7)</text>
    <text x="45" y="108" fill="#e4e4e7" font-size="13">ABA, ICBA + 76 asoc. estatales</text>
    <text x="45" y="129" fill="#e4e4e7" font-size="13">~80 grupos, carta conjunta</text>
    <text x="45" y="157" fill="#a1a1aa" font-size="13">Se opone a la Sección 404</text>
    <text x="45" y="178" fill="#a1a1aa" font-size="13">de recompensas stablecoin</text>
    <rect x="360" y="55" width="310" height="140" rx="10" fill="#0e2a1e" stroke="#4ade80" stroke-width="1.3"/>
    <text x="515" y="80" fill="#86efac" font-size="14" font-weight="700" text-anchor="middle">Apoyo Policial</text>
    <text x="375" y="108" fill="#e4e4e7" font-size="13">NOBLE (antes) + FLEOA (7/10)</text>
    <text x="375" y="129" fill="#e4e4e7" font-size="13">FLEOA: +70.000 miembros</text>
    <text x="375" y="157" fill="#a1a1aa" font-size="13">Pide ajustar la cláusula DeFi,</text>
    <text x="375" y="178" fill="#a1a1aa" font-size="13">pero respalda la ley en general</text>
    <rect x="30" y="210" width="640" height="110" rx="10" fill="#1c1c1e" stroke="#71717a" stroke-width="1.2"/>
